#include <stdio.h>
#include <stdlib.h>

long long neededDays(int *w, int n, long long cap) {
    long long days = 1, cur = 0;
    for (int i = 0; i < n; ++i) {
        if (cur + w[i] <= cap) {
            cur += w[i];
        } else {
            ++days;
            cur = w[i];
        }
    }
    return days;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, days; scanf("%d %d", &N, &days);
        int *weights = (int*)malloc(N * sizeof(int));
        long long lo = 0, hi = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &weights[i]);
            if (weights[i] > lo) lo = weights[i];
            hi += weights[i];
        }
        long long ans = hi, L = lo, R = hi;
        while (L <= R) {
            long long mid = L + (R - L) / 2;
            if (neededDays(weights, N, mid) <= days) {
                ans = mid;
                R = mid - 1;
            } else {
                L = mid + 1;
            }
        }
        printf("%lld\n", ans);
        free(weights);
    }
    return 0;
}

