import sys

def needed_days(weights, cap):
    days = 1
    cur = 0
    for w in weights:
        if cur + w <= cap:
            cur += w
        else:
            days += 1
            cur = w
    return days

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        days = int(next(it))
        weights = [int(next(it)) for _ in range(N)]
        lo = max(weights)
        hi = sum(weights)
        while lo < hi:
            mid = (lo + hi) // 2
            if needed_days(weights, mid) <= days:
                hi = mid
            else:
                lo = mid + 1
        out_lines.append(str(lo))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

